<template>
	<div :style='{"padding":"0 0 20px","margin":"0px auto","color":"#666","background":"#fff","width":"1200px","fontSize":"16px","position":"relative"}'>
		<div class="section-title" :style='{"padding":"0","margin":"0 1060px 20px 0","color":"#fff","borderRadius":"0px 0px 30px 30px","textAlign":"center","background":"#5FB6B8","display":"inline-block","width":"190px","fontSize":"22px","lineHeight":"60px","height":"60px"}'>зЎ®и®Ө{{totalPrice>0?'дёӢеҚ•':'йў„и®ў'}}</div>
		<el-descriptions v-if="seat!=1" title="йҖүжӢ©ж”¶иҙ§ең°еқҖ"></el-descriptions>
		<el-table v-if="seat!=1"
			:data="addressList"
			style="width: 100%;padding: 0 10px;">
			<el-table-column
				label="йҖүжӢ©"
				width="55">
				<template slot-scope="scope">
					<el-radio
						v-model="radio"
						:label="scope.$index"
						@change.native="getCurrentRow(scope.$index)">
						&nbsp;</el-radio>
				</template>
			</el-table-column>
			<el-table-column
				label="ж”¶д»¶дәә"
				prop="name">
			</el-table-column>
			<el-table-column
				label="иҒ”зі»ж–№ејҸ"
				prop="phone">
			</el-table-column>
			<el-table-column
				label="ең°еқҖ"
				prop="address">
			</el-table-column>
		</el-table>
		<div style="width:100%;display:flex;align-items:center;justify-content:center;margin:10px 0">
			<el-button type="success" @click="addAddress">ж·»еҠ ж”¶иҙ§ең°еқҖ</el-button>
		</div>
		<el-descriptions title="жё…еҚ•еҲ—иЎЁ"></el-descriptions>
		<el-table
			:data="tableData"
			style="width: 100%">
			<el-table-column
				label="е•Ҷе“ҒеҗҚз§°">
				<template slot-scope="scope">
					<div class="shangpin">
						<el-image
							style="width: 100px; height: 100px;flex: 1"
							:src="baseUrl + scope.row.picture"
							fit="fill"></el-image>
						<span style="margin-left: 10px;flex: 1">{{ scope.row.goodname }}</span>
					</div>
				</template>
			</el-table-column>
			<el-table-column v-if="totalPrice>0"
				label="д»·ж ј">
				<template slot-scope="scope">
					<span v-if="type == 2">{{ scope.row.price }} з§ҜеҲҶ</span>
					<span v-else><span :style='{"fontSize":"12px"}'>пҝҘ</span>{{ scope.row.price }}</span>
				</template>
			</el-table-column>
			<el-table-column v-if="seat==1"
				label="еә§дҪҚ">
				<template slot-scope="scope">
					<span>{{ scope.row.activeSeat }}</span>
				</template>
			</el-table-column>
			<el-table-column v-if="seat!=1"
				label="ж•°йҮҸ">
				<template slot-scope="scope">
					<span>{{ scope.row.buynumber }}</span>
				</template>
			</el-table-column>
			<el-table-column v-if="totalPrice>0"
				label="жҖ»д»·">
				<template slot-scope="scope">
					<span v-if="type == 2">{{ scope.row.price * scope.row.buynumber }} з§ҜеҲҶ</span>
					<span v-else><span :style='{"fontSize":"12px"}'>пҝҘ</span>{{ changePrice(scope.row) }}</span>
				</template>
			</el-table-column>
		</el-table>
		<div style="width: 100%;padding: 12px;box-sizing: border-box;display: flex;align-items: center;" v-if="type!=2">
			<span style="width: 80px; font-size: 14px;">дјҳжғ еҲёпјҡ</span>
			<el-button v-if="!nowCoupon.id" @click="changeCoupon">йҖүжӢ©дјҳжғ еҲё</el-button>
			<el-button v-if="nowCoupon.id" type="success" @click="changeCoupon">ж»Ў{{nowCoupon.fullamount}}еҮҸ{{nowCoupon.discountamount}}</el-button>
		</div>
		<div style="width: 100%;padding: 12px;box-sizing: border-box;display: flex;align-items: center;">
			<span style="width: 80px; font-size: 14px;">еӨҮжіЁпјҡ</span><el-input type="textarea" v-model="remark" placeholder="еӨҮжіЁ" style="width: calc(100% - 80px);"></el-input>
		</div>
		<div class="buy" v-if="seat!=1 && tableData.length > 0">
			<template v-if="type == 2">
				<span style="color: red;margin-right: 10px;font-weight: 700;">жҖ»д»·пјҡ{{totalPrice}} з§ҜеҲҶ</span>
				<el-button type="warning" @click="jfClick">е…‘жҚў</el-button>
			</template>
			<template v-else>
				<span style="color: red;margin-right: 10px;font-weight: 700;">жҖ»д»·пјҡ<span :style='{"fontSize":"12px"}'>пҝҘ</span>{{totalPrice}}</span>
				<el-button type="success" @click="payClick">ж”Ҝд»ҳ</el-button>
			</template>
		</div>
		<div class="buy" v-if="seat==1 && tableData.length > 0">
			<template v-if="type == 2">
				<span style="color: red;margin-right: 10px;font-weight: 700;">жҖ»д»·пјҡ{{totalPrice}} з§ҜеҲҶ</span>
				<el-button type="success" @click="xzJfClick">е…‘жҚў</el-button>
			</template>
			<template v-else>
				<span style="color: red;margin-right: 10px;font-weight: 700;" v-if="totalPrice>0">жҖ»д»·пјҡ<span :style='{"fontSize":"12px"}'>пҝҘ</span>{{totalPrice}}</span>
				<el-button type="success" @click="xzPayClick">{{totalPrice>0?'ж”Ҝд»ҳ':'йў„и®ў'}}</el-button>
			</template>
		</div>
		<el-dialog
			title="дјҳжғ еҲё"
			:visible.sync="couponVisible"
			width="85%">
			<div class="coupon_list">
				<div class="coupon" v-for="(item,index) in couponList" :key="index" :class="!changeStatus(item)?'coupons':''">
					<div class="coupon_left">
						<div class="name">{{item.name}}</div>
						<div class="name">ж»Ў{{item.fullamount}}еҮҸ{{item.discountamount}}</div>
						<div class="date">{{item.startime}}-{{item.endtime}}</div>
						<div class="date">{{item.remark}}</div>
						<div class="date1" v-if="item.dianpumingcheng">д»…йҷҗ {{item.dianpumingcheng}} е•Ҷе“ҒдҪҝз”Ё</div>
						<div class="date1" v-else>е…Ёе“Ғзұ»е•Ҷе“ҒеҸҜдҪҝз”Ё</div>
					</div>
					<div class="coupon_right">
						<div class="price">пҝҘ<span class="num">{{item.discountamount}}</span></div>
						<div class="btn" @click="takeCoupon(item)" v-if="item.status=='еҸҜдҪҝз”Ё'">
							{{changeStatus(item)?'з«ӢеҚідҪҝз”Ё':'дёҚж»ЎжқЎд»¶'}}</div>
					</div>
					<img v-if="item.status=='е·ІиҝҮжңҹ'" class="no-coupon" src="@/assets/no-coupon.png" alt="">
					<img v-if="item.status=='е·ІдҪҝз”Ё'" class="no-coupon" src="@/assets/finish-coupon.png" alt="">
				</div>
				<div class="noList" v-if="!couponList.length">
					жҡӮж— дјҳжғ еҲё
				</div>
				<div v-if="nowCoupon.id">
					<el-button @click="clearCoupon" size='mini'>дёҚдҪҝз”Ёдјҳжғ еҲё</el-button>
				</div>
			</div>
		</el-dialog>
	</div>
</template>

<script>
import config from '@/config/config'
export default {
	data() {
		return {
			baseUrl: config.baseUrl,
			userTableName: localStorage.getItem('UserTableName'),
			addressList: [],
			tableData: [],
			currentRow: null,
			radio: -1,
			order: {
				address: "",
				buynumber: 0,
				consignee: '',
				discountprice: 0,
				discounttotal: 0,
				goodid: 0,
				goodname: "",
				dianpumingcheng : "",
				orderid: "",
				picture: "",
				price: 0,
				status: "жңӘж”Ҝд»ҳ",
				tablename: "",
				tel: "",
				total: 0,
				type: 1,
				userid: localStorage.getItem('frontUserid')
			},
			user: {},
			type: 0,
			seat: 0,
			buynumber: 0,
			remark:'',
			couponVisible:false,
			nowCoupon:{
				
			},
			couponList: [],
			orderIdList: {},
			rightType:false,
			name: ''
		}
	},
	created() {
		if(this.$route.query.type != undefined) {
			this.type = this.$route.query.type;
		}
		if(this.$route.query.seat != undefined) {
			this.seat = this.$route.query.seat;
		}
		if(this.$route.query.tablename != undefined) {
			this.order.tablename = this.$route.query.tablename;
		}
		this.getSession();
		this.getAddrList();
		// иҺ·еҸ–е•Ҷе“Ғиҙӯд№°зҡ„жё…еҚ•еҲ—иЎЁ
		var orderGoods = localStorage.getItem('orderGoods')
		// иҪ¬жҚўжҲҗjsonзұ»еһӢпјҢlocalstorageдҝқеӯҳзҡ„жҳҜstringж•°жҚ®
		this.tableData = JSON.parse(orderGoods);
		this.changeShangpin()
		this.type = this.$route.query.type;
	},
	methods: {
		changeShangpin(){
			if(this.tableData.length==1){
				this.rightType = true
			}
			let name = ''
			this.tableData.forEach((item,index)=>{
				if(index==0){
					name = item.dianpumingcheng
					this.rightType = true
				}else{
					if(item.dianpumingcheng != name){
						this.rightType = false
					}
				}
			})
			if(this.rightType){
				this.name = name
			}
		},
		changePrice(row){
			let price = 0
			price = row.price * row.buynumber
			let discountamount = 0
			let totalPrice = 0
			this.tableData.forEach(item => {
				totalPrice += item.price * item.buynumber;
			})
			if(this.nowCoupon.id){
				discountamount = Number(((Number(price.toFixed(2)) / Number(totalPrice.toFixed(2))) * this.nowCoupon.discountamount).toFixed(2))
			}
			price = price - discountamount
			row.total = (price).toFixed(2)
			return (price).toFixed(2)
		},
		clearCoupon(){
			this.nowCoupon = {}
			this.$forceUpdate()
		},
		changeStatus(row) {
			let total = JSON.parse(JSON.stringify(this.totalPrice))
			if(this.nowCoupon.id){
				total = Number(total) + Number(this.nowCoupon.discountamount)
			}
			
			if (row.fullamount <= total) {
				if (row.status=='еҸҜдҪҝз”Ё') {
					if(row.dianpumingcheng&&this.rightType){
						if(row.dianpumingcheng.indexOf(this.name) > -1){
							return true
						}
					}else if(row.dianpumingcheng&&!this.rightType){
						return false
						
					}else {
						return true
					}
				}
			}
			return false
		},
		takeCoupon(row){
			if (!this.changeStatus(row)) {
				return false
			}
			this.nowCoupon = row
			this.couponVisible = false
		},
		changeCoupon(){
			this.couponVisible = true
			this.getMyList()
		},
		getMyList() {
			this.$http.get('mycoupon/page').then(res => {
				if (res.data && res.data.code == 0) {
					for (let x in res.data.data.list) {
						if (!this.isBetweenTime(this.getCurDateTime(), [res.data.data.list[x].startime, res
								.data.data.list[x].endtime
							]) && res.data.data.list[x].status != 'е·ІдҪҝз”Ё' && res.data.data.list[x].status !=
							'е·ІиҝҮжңҹ') {
							res.data.data.list[x].status = 'е·ІиҝҮжңҹ'
							this.$http.post('mycoupon/update', res.data.data.list[x]).then(obj => {})
						} else if (this.isBetweenTime(this.getCurDateTime(), [res.data.data.list[x]
								.startime, res.data.data.list[x].endtime
							]) && res.data.data.list[x].status != 'е·ІдҪҝз”Ё' && res.data.data.list[x].status !=
							'еҸҜдҪҝз”Ё') {
							res.data.data.list[x].status = 'еҸҜдҪҝз”Ё'
							this.$http.post('mycoupon/update', res.data.data.list[x]).then(obj => {})
						}
		
					}
					this.couponList = res.data.data.list
				}
			})
		},
		isBetweenTime(currentDate, timeQuantum) {
			let isBetween = true;
			let currentTime = new Date(currentDate);
			let startTime = new Date(timeQuantum[0]);
			let endTime = new Date(timeQuantum[1]);
			let t1 = currentTime.getTime() - startTime.getTime();
			let t2 = currentTime.getTime() - endTime.getTime();
			if (t1 < 0 || t2 > 0) {
				isBetween = false;
			}
			return isBetween;
		},
		getSession() {
			if(!this.userTableName){
				this.$router.push('/login');
				return false
			}
			this.$http.get(`${this.userTableName}/session`, {emulateJSON: true}).then(res => {
				if (res.data.code == 0) {
					this.user = res.data.data;
				}
			});
		},
		getCurrentRow(index) {
			this.radio = index;гҖҖ
		},
		getAddrList() {
			this.$http.get('address/list', {params: {userid: localStorage.getItem('frontUserid')}}).then(res => {
				if (res.data.code == 0) {
					this.addressList = res.data.data.list;
					this.addressList.forEach((item, index) => {
						if (item.isdefault == 'жҳҜ') {
							this.radio = index;
						}
					});
				}
			});
		},
		addAddress(){
			this.$router.push('/index/shop-address/addOrUpdate');
		},
		// жӯЈеёёдёӢеҚ•пјҢз”ҹжҲҗи®ўеҚ•пјҢеҮҸе°‘дҪҷйўқпјҢж·»еҠ з§ҜеҲҶпјҢеҮҸе°‘еә“еӯҳпјҢдҝ®ж”№зҠ¶жҖҒе·Іж”Ҝд»ҳ
		 payClick() {
			let that = this
			if (this.radio == -1) {
				this.$message({
					message: 'иҜ·йҖүжӢ©ж”¶иҙ§ең°еқҖ',
					type: 'error',
					duration: 1500
				});
				return;
			}
			var orderno = this.createOrder() + 1
			// з”ҹжҲҗи®ўеҚ•
			for(let index in this.tableData){
				let item = this.tableData[index]
				setTimeout(()=>{
					
				// иҺ·еҸ–е•Ҷе“ҒиҜҰжғ…дҝЎжҒҜ
				 this.$http.get(`${item.tablename}/info/${item.goodid}`).then( res => {
					// и®ўеҚ•зј–еҸ·
					this.orderIdList['orderId' + Number(index)] = String(this.createOrder())
					let data = res.data.data;
					if(item.tablename=='shangpinxinxi'){
						// еҮҸе°‘еә“еӯҳ
						data.alllimittimes = data.alllimittimes - item.buynumber;
						if(data.alllimittimes==0){
							data.onshelves = 0
						}
					}
					// жӣҙж–°еә“еӯҳдҝЎжҒҜ
					 this.$http.post(`${item.tablename}/update`, data).then( res => {
						// ж·»еҠ и®ўеҚ•дҝЎжҒҜ
						let order = {
							orderid: this.orderIdList['orderId' + Number(index)],
							tablename: item.tablename,
							userid: this.user.id,
							goodid: item.goodid,
							goodname: item.goodname,
							dianpumingcheng: item.dianpumingcheng,
							goodtype: item.goodtype,
							picture: item.picture,
							buynumber: item.buynumber,
							discountprice: item.price,
							price: item.price,
							total: Number(item.total),
							discounttotal: Number(item.total),
							type: this.type?Number(this.type):1,
							//total: this.totalPrice,
							address: this.addressList[this.radio].address,
							tel: this.addressList[this.radio].phone,
							consignee: this.addressList[this.radio].name,
							remark: this.remark,
							status: 'жңӘж”Ҝд»ҳ',
							sfsh: '',
							role: this.userTableName,
							orderno: orderno,
						}
						if (this.nowCoupon.id) {
							order.couponnumber = this.nowCoupon.couponnumber
							order.discountamount = this.nowCoupon.discountamount
							this.nowCoupon.status = 'е·ІдҪҝз”Ё'
							this.$http.post(`mycoupon/update`, this.nowCoupon)
						}
						this.$http.post('orders/add', order).then( res => {
							// еҲ йҷӨиҙӯзү©иҪҰж•°жҚ®(еҰӮжһңжҳҜиҙӯзү©иҪҰдёӢеҚ•)
							if (item.id) {
								this.$http.post('cart/delete', [item.id]).then(res => {});
							}
							// еҮҸе°‘дҪҷйўқпјҢжӣҙж–°и®ўеҚ•зҠ¶жҖҒ
							// еҲӨж–ӯдҪҷйўқжҳҜеҗҰе……и¶і
							if (Number(this.user.money) < Number(item.total)) {
								this.$message({
									message: 'дҪҷйўқдёҚи¶іпјҢиҜ·е…Ҳе……еҖј',
									type: 'error',
									duration: 1500,
								onClose(){
									that.$router.push('/index/center')
								}
								});
								return
							}
							// еҰӮжһңиҜҘе•Ҷе“ҒеӯҳеңЁз§ҜеҲҶ
							if (data.jf) {
								this.user.jf = Number((Number(this.user.jf) + Number(item.total)).toFixed(2))
							}
							this.user.money = Number((Number(this.user.money) - Number(item.total)).toFixed(2))
							// жӣҙж–°з”ЁжҲ·дҪҷйўқ
							this.$http.post(`${this.userTableName}/update`, this.user).then(res => {
								localStorage.setItem('sessionForm',JSON.stringify(this.user))
								order.status = 'е·Іж”Ҝд»ҳ'
								var params = {
									orderid: this.orderIdList['orderId' + Number(index)],
									page: 1,
									limit: 1,
								}
								this.$http.get('orders/list', {params: params}).then(res => {
									order.id = res.data.data.list[0].id;
									this.$http.post(`orders/update`, order).then(res => {
										
										this.$message({
											message: 'иҙӯд№°жҲҗеҠҹ',
											type: 'success',
											duration: 1500,
											onClose: () => {
												this.$router.push('/index/shop-order/order');
											}
										});
									});
								});
							});
						});
					});
				});
				},500)
			}
		},
		createOrder() {
			let order = '';
			let now = new Date();
			order += now.getFullYear();
			order += now.getMonth() + 1;
			order += now.getDate();
			order += now.getHours();
			order += now.getMinutes();
			order += now.getSeconds();
			order += now.getMilliseconds();

			return order;
		}
	},
	computed: {
		totalPrice() {
			let totalPrice = 0;
			this.tableData.forEach(item => {
				totalPrice += item.price * item.buynumber;
			});
			if(this.nowCoupon.id){
				totalPrice = totalPrice - this.nowCoupon.discountamount
			}
			if(totalPrice<0){
				totalPrice = 0
			}
			return totalPrice.toFixed(2);
		},
		totalJifen() {
			let totalJifen = 0;
			this.tableData.forEach(item => {
				totalJifen += parseInt(item.jf * this.buynumber);
			});

			return totalJifen;
		},
	}
}
</script>

<style rel="stylesheet/scss" lang="scss" scoped>
  .section {
	width: 900px;
	margin: 0 auto;
  }

  .shangpin {
	display: flex;
  }
  .buy {
	text-align: right;
	padding-right: 82px;
  }
  .coupon_list {
	width: 100%;
	display: flex;
	flex-wrap: wrap;
  
	.coupon {
		width: 31%;
		background: url('../../assets/coupon.png');
		background-repeat: no-repeat;
		background-position: center center;
		background-size: cover;
		padding: 60px 30px;
		display: flex;
		align-items: center;
		margin: 0 1% 20px;
  
		position: relative;
  
		.no-coupon {
			position: absolute;
			width: 80px;
			right: 20px;
			top: 20px;
		}
  
		.coupon_left {
			flex: 1;
			color: #000;
  
			.name {
				font-size: 22px;
				line-height: 1.5;
			}
  
			.date {
				font-size: 14px;
				line-height: 1.5;
			}
			.date1 {
				font-size: 12px;
				line-height: 1.5;
				color: #FF0800;
			}
		}
  
		.coupon_right {
			display: flex;
			flex-direction: column;
			align-items: center;
  
			.price {
