<script>
	import 'animate.css';

export default {
    //ж•°жҚ®йӣҶеҗҲ
    data() {
		return {
            pageFlag : '',
			tableName: '',
			registerForm: {},
			forgetForm: {},
			rules: {},
			requiredRules: {},
            yonghuxingbieOptions: [],
            shangjiaxingbieOptions: [],
            smscode:'',
			//еҖ’и®Ўж—¶60s
			count: 60,
			//еҖ’и®Ўж—¶е®ҡж—¶еҷЁ
			inter: null,
			//еҖ’и®Ўз»“жқҹж ҮиҜҶ
			isEndFlag: true,
		}
    },
	mounted() {
		if(this.$route.query.pageFlag=='register'){
			this.tableName = this.$route.query.role;
			if(this.tableName=='yonghu'){
				this.registerForm = {
					yonghuming: '',
					mima: '',
					mima2: '',
					xingming: '',
					touxiang: '',
					xingbie: '',
					nianling: '',
					youxiang: '',
					mobile: '',
					money: '',
				}
			}
			if(this.tableName=='shangjia'){
				this.registerForm = {
					dianpumingcheng: '',
					mima: '',
					mima2: '',
					shangjiaxingming: '',
					touxiang: '',
					xingbie: '',
					nianling: '',
					youxiang: '',
					mobile: '',
					money: '',
				}
			}
			if ('yonghu' == this.tableName) {
				this.rules.yonghuming = [{ required: true, message: 'иҜ·иҫ“е…Ҙз”ЁжҲ·еҗҚ', trigger: 'blur' }];
				this.requiredRules.yonghuming = [{ required: true, message: 'иҜ·иҫ“е…Ҙз”ЁжҲ·еҗҚ', trigger: 'blur' }]
			}
			if ('yonghu' == this.tableName) {
				this.rules.mima = [{ required: true, message: 'иҜ·иҫ“е…ҘеҜҶз Ғ', trigger: 'blur' }];
				this.requiredRules.mima = [{ required: true, message: 'иҜ·иҫ“е…ҘеҜҶз Ғ', trigger: 'blur' }]
			}
			if ('yonghu' == this.tableName) {
				this.rules.xingming = [{ required: true, message: 'иҜ·иҫ“е…Ҙе§“еҗҚ', trigger: 'blur' }];
				this.requiredRules.xingming = [{ required: true, message: 'иҜ·иҫ“е…Ҙе§“еҗҚ', trigger: 'blur' }]
			}
			this.yonghuxingbieOptions = "з”·,еҘі".split(',');
			if ('yonghu' == this.tableName) {
				this.rules.nianling = [{ required: true, validator: this.$validate.isIntNumer, trigger: 'blur' }];
			}
			if ('yonghu' == this.tableName) {
				this.rules.youxiang = [{ required: true, validator: this.$validate.isEmail, trigger: 'blur' }];
			}
			if ('yonghu' == this.tableName) {
				this.rules.mobile = [{ required: true, validator: this.$validate.isMobile, trigger: 'blur' }];
			}
			if ('yonghu' == this.tableName) {
				this.rules.money = [{ required: true, validator: this.$validate.isNumber, trigger: 'blur' }];
			}
			if ('shangjia' == this.tableName) {
				this.rules.dianpumingcheng = [{ required: true, message: 'иҜ·иҫ“е…Ҙеә—й“әеҗҚз§°', trigger: 'blur' }];
				this.requiredRules.dianpumingcheng = [{ required: true, message: 'иҜ·иҫ“е…Ҙеә—й“әеҗҚз§°', trigger: 'blur' }]
			}
			if ('shangjia' == this.tableName) {
				this.rules.mima = [{ required: true, message: 'иҜ·иҫ“е…ҘеҜҶз Ғ', trigger: 'blur' }];
				this.requiredRules.mima = [{ required: true, message: 'иҜ·иҫ“е…ҘеҜҶз Ғ', trigger: 'blur' }]
			}
			if ('shangjia' == this.tableName) {
				this.rules.shangjiaxingming = [{ required: true, message: 'иҜ·иҫ“е…Ҙе•Ҷе®¶е§“еҗҚ', trigger: 'blur' }];
				this.requiredRules.shangjiaxingming = [{ required: true, message: 'иҜ·иҫ“е…Ҙе•Ҷе®¶е§“еҗҚ', trigger: 'blur' }]
			}
			this.shangjiaxingbieOptions = "з”·,еҘі".split(',');
			if ('shangjia' == this.tableName) {
				this.rules.nianling = [{ required: true, validator: this.$validate.isIntNumer, trigger: 'blur' }];
			}
			if ('shangjia' == this.tableName) {
				this.rules.youxiang = [{ required: true, validator: this.$validate.isEmail, trigger: 'blur' }];
			}
			if ('shangjia' == this.tableName) {
				this.rules.mobile = [{ required: true, validator: this.$validate.isMobile, trigger: 'blur' }];
			}
			if ('shangjia' == this.tableName) {
				this.rules.money = [{ required: true, validator: this.$validate.isNumber, trigger: 'blur' }];
			}
		}
	},
    created() {
		this.pageFlag = this.$route.query.pageFlag;
    },
    //ж–№жі•йӣҶеҗҲ
    methods: {
		changeRules(name){
			if(this.requiredRules[name]){
				return true
			}
			return false
		},
		// иҺ·еҸ–uuid
		getUUID () {
			return new Date().getTime();
		},
        // дёӢдәҢйҡҸ
		yonghutouxiangUploadChange(fileUrls) {
			this.registerForm.touxiang = fileUrls.replace(new RegExp(this.$config.baseUrl,"g"),"");
		},
		shangjiatouxiangUploadChange(fileUrls) {
			this.registerForm.touxiang = fileUrls.replace(new RegExp(this.$config.baseUrl,"g"),"");
		},

		// еӨҡзә§иҒ”еҠЁеҸӮж•°

		sendsmscode() {
			if(!this.registerForm.mobile){
				this.$message.error(`жүӢжңәеҸ·з ҒдёҚиғҪдёәз©ә`);
				return
			}
			let mobileF = this.$validate.isMobile2(this.registerForm.mobile);
			if(this.registerForm.mobile&&(!this.$validate.isMobile2(this.registerForm.mobile))){
				this.$message.error(`иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„жүӢжңәж јејҸ`);
				return
			}
			this.isEndFlag = false;
			var _this = this;
			this.inter = window.setInterval(function() {
				_this.count = _this.count - 1;
				if (_this.count <= 0) {
					window.clearInterval(_this.inter);
					_this.isEndFlag = true;
					_this.count=60;
				}
			}, 1000);
			this.$http({
				url: `${this.tableName}/sendsms?mobile=`+this.registerForm.mobile,
				method: "get",
				params: {}
			}).then(({ data }) => {
				if (data && data.code === 0) {
					this.$message.success(`еҸ‘йҖҒжҲҗеҠҹ`);
				} else {
					this.$message.error(`жңҚеҠЎеҷЁејӮеёёпјҢиҜ·зЁҚеҗҺйҮҚиҜ•`)
				}
			});
		},

		submitForm(formName) {
			this.$refs[formName].validate((valid) => {
				if (valid) {
					var url=this.tableName+"/register";
					if(`yonghu` == this.tableName ){
						url=this.tableName+"/register?smscode="+this.smscode;
						if(this.registerForm.mobile&&(!this.$validate.isMobile2(this.registerForm.mobile))){
							this.$message.error(`иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„жүӢжңәж јејҸ`);
							return
						}
					}
					if((!this.smscode) && `yonghu` == this.tableName){
						this.$message.error(`йӘҢиҜҒз ҒдёҚиғҪдёәз©ә`);
						return
					}
					if(`yonghu` == this.tableName && this.registerForm.mima!=this.registerForm.mima2) {
						this.$message.error(`дёӨж¬ЎеҜҶз Ғиҫ“е…ҘдёҚдёҖиҮҙ`);
						return
					}
					if(`shangjia` == this.tableName ){
						url=this.tableName+"/register?smscode="+this.smscode;
						if(this.registerForm.mobile&&(!this.$validate.isMobile2(this.registerForm.mobile))){
							this.$message.error(`иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„жүӢжңәж јејҸ`);
							return
						}
					}
					if((!this.smscode) && `shangjia` == this.tableName){
						this.$message.error(`йӘҢиҜҒз ҒдёҚиғҪдёәз©ә`);
						return
					}
					if(`shangjia` == this.tableName && this.registerForm.mima!=this.registerForm.mima2) {
						this.$message.error(`дёӨж¬ЎеҜҶз Ғиҫ“е…ҘдёҚдёҖиҮҙ`);
						return
					}
					this.$http.post(url, this.registerForm).then(res => {
						if (res.data.code === 0) {
							this.$message({
								message: 'жіЁеҶҢжҲҗеҠҹ',
								type: 'success',
								duration: 1500,
								onClose: () => {
									this.$router.push('/login');
								}
							});
						} else {
							this.$message.error(res.data.msg);
						}
					});
				} else {
					return false;
				}
			});
		},
		resetForm(formName) {
			this.$refs[formName].resetFields();
		}
    }
}
</script>

