					placeholder="еӨҮжіЁ" clearable :disabled=" false  ||ro.remark"></el-input>
			</el-form-item>
			<el-form-item class="add-item"  label="зҠ¶жҖҒ" prop="status">
				<el-select v-model="ruleForm.status" placeholder="иҜ·йҖүжӢ©зҠ¶жҖҒ" :disabled=" false  ||ro.status" >
					<el-option
						v-for="(item,index) in statusOptions"
						:key="index"
						:label="item"
						:value="item">
					</el-option>
				</el-select>
			</el-form-item>
			<el-form-item class="add-item" label="е•ҶжҲ·еҗҚз§°" prop="dianpumingcheng">
