<script>
	export default {
		data() {
			return {
				id: '',
				baseUrl: '',
				ro:{
					userid : false,
					couponid : false,
					name : false,
					couponnumber : false,
					fullamount : false,
					discountamount : false,
					startime : false,
					endtime : false,
					type : false,
					remark : false,
					status : false,
					dianpumingcheng : false,
				},
				type: '',
				userTableName: localStorage.getItem('UserTableName'),
				ruleForm: {
					userid: '',
					couponid: '',
					name: '',
					couponnumber: '',
					fullamount: '',
					discountamount: '',
					startime: '',
					endtime: '',
					type: '',
					remark: '',
					status: '',
					dianpumingcheng: '',
				},
				statusOptions: [],


				rules: {
					userid: [
						{ required: true, message: 'з”ЁжҲ·idдёҚиғҪдёәз©ә', trigger: 'blur' },
					],
					couponid: [
						{ required: true, message: 'дјҳжғ еҲёidдёҚиғҪдёәз©ә', trigger: 'blur' },
					],
					name: [
						{ required: true, message: 'еҗҚз§°дёҚиғҪдёәз©ә', trigger: 'blur' },
					],
					couponnumber: [
						{ required: true, message: 'еҲёзј–еҸ·дёҚиғҪдёәз©ә', trigger: 'blur' },
					],
					fullamount: [
						{ required: true, message: 'ж»ЎйўқдёҚиғҪдёәз©ә', trigger: 'blur' },
						{ validator: this.$validate.isNumber, trigger: 'blur' },
					],
					discountamount: [
						{ required: true, message: 'дјҳжғ йўқдёҚиғҪдёәз©ә', trigger: 'blur' },
						{ validator: this.$validate.isNumber, trigger: 'blur' },
					],
					startime: [
					],
					endtime: [
					],
					type: [
					],
					remark: [
					],
					status: [
					],
					dianpumingcheng: [
					],
				},
				centerType: false,
			};
		},
		computed: {



		},
		components: {
		},
		created() {
			if(this.$route.query.centerType){
				this.centerType = true
			}
			//this.bg();
			let type = this.$route.query.type ? this.$route.query.type : '';
			this.init(type);
			this.baseUrl = this.$config.baseUrl;
		},
		methods: {
			getMakeZero(s) {
				return s < 10 ? '0' + s : s;
			},
			// дёӢиҪҪ
			download(file){
				window.open(`${file}`)
			},
			// еҲқе§ӢеҢ–
			init(type) {
				this.type = type;
				if(type=='cross'){
					var obj = JSON.parse(localStorage.getItem('crossObj'));
					for (var o in obj){
						if(o=='userid'){
							this.ruleForm.userid = obj[o];
							this.ro.userid = true;
							continue;
						}
						if(o=='couponid'){
							this.ruleForm.couponid = obj[o];
							this.ro.couponid = true;
							continue;
						}
						if(o=='name'){
							this.ruleForm.name = obj[o];
							this.ro.name = true;
							continue;
						}
						if(o=='couponnumber'){
							this.ruleForm.couponnumber = obj[o];
							this.ro.couponnumber = true;
							continue;
						}
						if(o=='fullamount'){
							this.ruleForm.fullamount = obj[o];
							this.ro.fullamount = true;
							continue;
						}
						if(o=='discountamount'){
							this.ruleForm.discountamount = obj[o];
							this.ro.discountamount = true;
							continue;
						}
						if(o=='startime'){
							this.ruleForm.startime = obj[o];
							this.ro.startime = true;
							continue;
						}
						if(o=='endtime'){
							this.ruleForm.endtime = obj[o];
							this.ro.endtime = true;
							continue;
						}
						if(o=='type'){
							this.ruleForm.type = obj[o];
							this.ro.type = true;
							continue;
						}
						if(o=='remark'){
							this.ruleForm.remark = obj[o];
							this.ro.remark = true;
							continue;
						}
						if(o=='status'){
							this.ruleForm.status = obj[o];
							this.ro.status = true;
							continue;
						}
						if(o=='dianpumingcheng'){
							this.ruleForm.dianpumingcheng = obj[o];
							this.ro.dianpumingcheng = true;
							continue;
						}
					}
				}else if(type=='edit'){
					this.info()
				}
				this.statusOptions = "еҸҜдҪҝз”Ё,е·ІдҪҝз”Ё,е·ІиҝҮжңҹ".split(',')

				if (localStorage.getItem('raffleType') && localStorage.getItem('raffleType') != null) {
					localStorage.removeItem('raffleType')
					setTimeout(() => {
						this.onSubmit()
					}, 300)
				}
			},

			// еӨҡзә§иҒ”еҠЁеҸӮж•°
			// еӨҡзә§иҒ”еҠЁеҸӮж•°
			info() {
				this.$http.get(`mycoupon/detail/${this.$route.query.id}`, {emulateJSON: true}).then(res => {
					if (res.data.code == 0) {
						this.ruleForm = res.data.data;
					}
				});
			},
			// жҸҗдәӨ
			async onSubmit() {
				if(!this.ruleForm.id) {
					delete this.ruleForm.userid
				}
				await this.$refs["ruleForm"].validate(async valid => {
					if(valid) {
						if(this.type=='cross'){
							var statusColumnName = localStorage.getItem('statusColumnName');
							var statusColumnValue = localStorage.getItem('statusColumnValue');
							if(statusColumnName && statusColumnName!='') {
								var obj = JSON.parse(localStorage.getItem('crossObj'));
								if(!statusColumnName.startsWith("[")) {
									for (var o in obj){
										if(o==statusColumnName){
											obj[o] = statusColumnValue;
										}
									}
									var table = localStorage.getItem('crossTable');
									await this.$http.post(table+'/update', obj).then(res => {});
								}
							}
						}


						await this.$http.post(`mycoupon/${this.ruleForm.id?'update':this.centerType?'save':'add'}`, this.ruleForm).then(async res => {
							if (res.data.code == 0) {
								this.$message({
									message: 'ж“ҚдҪңжҲҗеҠҹ',
									type: 'success',
									duration: 1500,
									onClose: () => {
										this.$router.go(-1);
										
									}
								});
							} else {
								this.$message({
									message: res.data.msg,
									type: 'error',
									duration: 1500
								});
							}
						});
					}
				});
			},
			// иҺ·еҸ–uuid
			getUUID () {
				return new Date().getTime();
			},
			// иҝ”еӣһ
			back() {
				this.$router.go(-1);
			},
		}
	};
</script>

