		</div>
	
		<el-tabs class="center-tabs" tab-position="left" @tab-click="handleClick">
			<el-tab-pane label="дёӘдәәдёӯеҝғ">
				<el-form class="center-preview-pv" ref="sessionForm" :model="sessionForm" :rules="rules" label-width="180px">
					<el-form-item class="center-item" v-if="userTableName=='yonghu'" label="з”ЁжҲ·еҗҚ" prop="yonghuming">
						<el-input v-model="sessionForm.yonghuming" placeholder="з”ЁжҲ·еҗҚ" readonly></el-input>
					</el-form-item>
					<el-form-item class="center-item" v-if="userTableName=='yonghu'" label="е§“еҗҚ" prop="xingming">
						<el-input v-model="sessionForm.xingming" placeholder="е§“еҗҚ" ></el-input>
					</el-form-item>
					<el-form-item class="center-item" v-if="userTableName=='yonghu'" label="еӨҙеғҸ" prop="touxiang">
						<file-upload
							tip="зӮ№еҮ»дёҠдј еӨҙеғҸ"
							action="file/upload"
							:limit="1"
							:multiple="true"
							:fileUrls="sessionForm.touxiang?sessionForm.touxiang:''"
