					<el-form-item class="center-item" v-if="userTableName=='yonghu'" label="жҖ§еҲ«" prop="xingbie">
						<el-select v-model="sessionForm.xingbie" placeholder="иҜ·йҖүжӢ©жҖ§еҲ«" >
							<el-option v-for="(item, index) in dynamicProp.xingbie" :key="index" :label="item" :value="item"></el-option>
						</el-select>
					</el-form-item>
					<el-form-item class="center-item" v-if="userTableName=='yonghu'" label="е№ҙйҫ„" prop="nianling">
						<el-input v-model="sessionForm.nianling" placeholder="е№ҙйҫ„" ></el-input>
					</el-form-item>
					<el-form-item class="center-item" v-if="userTableName=='yonghu'" label="йӮ®з®ұ" prop="youxiang">
						<el-input v-model="sessionForm.youxiang" placeholder="йӮ®з®ұ" ></el-input>
					</el-form-item>
					<el-form-item class="center-item" v-if="userTableName=='yonghu'" label="жүӢжңәеҸ·" prop="mobile">
						<el-input v-model="sessionForm.mobile" placeholder="жүӢжңәеҸ·" ></el-input>
					</el-form-item>
					<el-form-item class="center-item" v-if="userTableName=='yonghu'" label="дҪҷйўқ">
						<div class="balance-item">
							<el-input v-model="sessionForm.money" placeholder="дҪҷйўқ" readonly></el-input>
							<div class="balanceBtn" @click="dialogFormVisibleMoney = true">
