							</div>
						</div>
					</el-form-item>
					<el-form-item class="center-btn-item">
						<div class="updateBtn" type="primary" @click="onSubmit('sessionForm')">
							<span class="icon iconfont icon-kaitongfuwu"></span>
							<span class="text">зЎ®е®ҡ</span>
						</div>
						<div class="closeBtn" type="danger" @click="logout">
							<span class="icon iconfont icon-shanchu1"></span>
							<span class="text">еҸ–ж¶Ҳ</span>
						</div>
					</el-form-item>
				</el-form>
			</el-tab-pane>
			<el-tab-pane label="дҝ®ж”№еҜҶз Ғ">
				<el-form class="center-preview-pv" ref="passwordForm" :model="passwordForm" :rules="passwordRules" label-width="180px">
					<el-form-item class="center-item" label="еҺҹеҜҶз Ғ" prop="password">
						<el-input type="password" v-model="passwordForm.password" placeholder="еҺҹеҜҶз Ғ"></el-input>
					</el-form-item>
					<el-form-item class="center-item" label="ж–°еҜҶз Ғ" prop="newpassword">
						<el-input type="password" v-model="passwordForm.newpassword" placeholder="ж–°еҜҶз Ғ"></el-input>
					</el-form-item>
					<el-form-item class="center-item" label="зЎ®и®ӨеҜҶз Ғ" prop="repassword">
						<el-input type="password" v-model="passwordForm.repassword" placeholder="зЎ®и®ӨеҜҶз Ғ"></el-input>
					</el-form-item>
					<el-form-item class="center-btn-item">
						<div class="updateBtn" type="primary" @click="updatePassword">
							<span class="icon iconfont icon-kaitongfuwu"></span>
							<span class="text">дҝ®ж”№еҜҶз Ғ</span>
						</div>
					</el-form-item>
				</el-form>
			</el-tab-pane>
			<el-tab-pane v-for="(item,index) in menuList" :key="index" v-if="hasBack(item.menu)" :label="item.child[0].menu" :name="item.child[0].tableName"></el-tab-pane>
			<el-tab-pane label="жҲ‘зҡ„и®ўеҚ•"></el-tab-pane>
			<el-tab-pane label="жҲ‘зҡ„ең°еқҖ" name="MyAddress">
				<router-view></router-view>
			</el-tab-pane>
			<el-tab-pane label="жҲ‘зҡ„ж”¶и—Ҹ"></el-tab-pane>
			<el-tab-pane label="жҲ‘зҡ„дјҳжғ еҲё">
				<div class="coupon_list">
					<div class="coupon" v-for="(item,index) in couponList" :key="index" :class="(item.status=='е·ІиҝҮжңҹ'||item.status=='е·ІдҪҝз”Ё')?'coupons':''">
						<div class="coupon_left">
							<div class="name">{{item.name}}</div>
							<div class="name">ж»Ў{{item.fullamount}}еҮҸ{{item.discountamount}}</div>
							<div class="date">{{item.startime}}-{{item.endtime}}</div>
							<div class="date">{{item.couponnumber}}</div>
							<div class="date">{{item.remark}}</div>
							<div class="date1" v-if="item.dianpumingcheng">д»…йҷҗ {{item.dianpumingcheng}} е•Ҷе“ҒдҪҝз”Ё</div>
							<div class="date1" v-else>е…Ёе“Ғзұ»е•Ҷе“ҒеҸҜдҪҝз”Ё</div>
						</div>
						<div class="coupon_right">
							<div class="price">пҝҘ<span class="num">{{item.discountamount}}</span></div>
							<div class="btn" v-if="item.status=='еҸҜдҪҝз”Ё'">{{item.status}}</div>
						</div>
						<img v-if="item.status=='е·ІиҝҮжңҹ'" class="no-coupon" src="@/assets/no-coupon.png" alt="">
						<img v-if="item.status=='е·ІдҪҝз”Ё'" class="no-coupon" src="@/assets/finish-coupon.png" alt="">
					</div>
					<div class="noList" v-if="!couponList.length">
						жҡӮж— дјҳжғ еҲё
					</div>
				</div>
			</el-tab-pane>
		</el-tabs>

		<el-dialog title="з”ЁжҲ·е……еҖј" :visible.sync="dialogFormVisibleMoney" width="726px" center>
			<el-form :model="chongzhiForm">
				<el-form-item label="е……еҖјйҮ‘йўқ" label-width="120px">
					<el-input type="number" v-model="chongzhiForm.money" autocomplete="off" placeholder="е……еҖјйҮ‘йўқ"></el-input>
				</el-form-item>
				<el-form-item label-width="120px">
					<el-radio-group v-model="chongzhiForm.radio">
						<el-radio style="margin-bottom: 30px" label="еҫ®дҝЎж”Ҝд»ҳ">
							<el-image
								style="width: 60px; height: 60px;vertical-align: middle;"
								:src="require('@/assets/weixin.png')"
								fit="fill"></el-image>
							<span style="display: inline-block;margin-left: 10px">еҫ®дҝЎж”Ҝд»ҳ</span>
						</el-radio>
						<el-radio label="ж”Ҝд»ҳе®қж”Ҝд»ҳ">
							<el-image
								style="width: 60px; height: 60px;vertical-align: middle;"
								:src="require('@/assets/zhifubao.png')"
								fit="fill"></el-image>
							<span style="display: inline-block;margin-left: 10px">ж”Ҝд»ҳе®қж”Ҝд»ҳ</span>
						</el-radio>
						<el-radio label="дёӯеӣҪе»әи®ҫй“¶иЎҢж”Ҝд»ҳ">
							<el-image
								style="width: 120px; height: 60px;vertical-align: middle;"
								:src="require('@/assets/jianshe.png')"
								fit="fill"></el-image>
						</el-radio>
						<el-radio label="дёӯеӣҪеҶңдёҡй“¶иЎҢж”Ҝд»ҳ">
							<el-image
								style="width: 126px; height: 60px;vertical-align: middle;"
								:src="require('@/assets/nongye.png')"
								fit="fill"></el-image>
						</el-radio>
						<el-radio label="дёӯеӣҪй“¶иЎҢж”Ҝд»ҳ">
							<el-image
								style="width: 140px; height: 60px;vertical-align: middle;"
								:src="require('@/assets/zhongguo.png')"
								fit="fill"></el-image>
						</el-radio>
						<el-radio label="дәӨйҖҡй“¶иЎҢж”Ҝд»ҳ">
							<el-image
								style="width: 120px; height: 60px;vertical-align: middle;"
								:src="require('@/assets/jiaotong.png')"
								fit="fill"></el-image>
						</el-radio>
					</el-radio-group>
				</el-form-item>
			</el-form>
			<div slot="footer" class="dialog-footer">
				<el-button @click="dialogFormVisibleMoney = false">еҸ– ж¶Ҳ</el-button>
				<el-button type="primary" @click="chongzhi">зЎ®и®Өе……еҖј</el-button>
			</div>
		</el-dialog>
	</div>
</template>

<script>
	import config from '@/config/config';
	import menu from '@/config/menu';
	import Vue from 'vue';
	export default {
		//ж•°жҚ®йӣҶеҗҲ
		data() {
			return {
				title: 'дёӘдәәдёӯеҝғ',
				baseUrl: config.baseUrl,
				sessionForm: {},
				passwordForm: {},
				passwordRules: {
					password: [
						{
							required: true,
							message: "еҜҶз ҒдёҚиғҪдёәз©ә",
							trigger: "blur"
						}
					],
					newpassword: [
						{
							required: true,
							message: "ж–°еҜҶз ҒдёҚиғҪдёәз©ә",
							trigger: "blur"
						}
					],
					repassword: [
						{
							required: true,
							message: "зЎ®и®ӨеҜҶз ҒдёҚиғҪдёәз©ә",
							trigger: "blur"
						}
					]
				},
				rules: {},
				chongzhiForm: {
					money: '',
					radio: ''
				},
				menuList: [],
				disabled: false,
				dialogFormVisibleMoney: false,
				uploadUrl: config.baseUrl + 'file/upload',
				imageUrl: '',
				headers: {Token: localStorage.getItem('frontToken')},
				userTableName: localStorage.getItem('UserTableName'),
				dynamicProp: {},
				couponList: [],
			}
		},
		created() {
			let menus = menu.list()
			for(let x in menus){
				if(menus[x].tableName == this.userTableName){
					for(let i in menus[x].backMenu){
						if(menus[x].backMenu[i].menu=='иҖғиҜ•з®ЎзҗҶ'){
							menus[x].backMenu.splice(i,1)
						}
					}
					this.menuList = menus[x].backMenu
				}
			}
			if ('yonghu' == this.userTableName) {
				this.$set(this.sessionForm, 'yonghuming', null);
			}
			if ('yonghu' == this.userTableName) {
				this.$set(this.sessionForm, 'mima', null);
			}
			if ('yonghu' == this.userTableName) {
				this.$set(this.sessionForm, 'xingming', null);
			}
			if ('yonghu' == this.userTableName) {
				this.$set(this.sessionForm, 'touxiang', null);
			}
			if ('yonghu' == this.userTableName) {
				this.$set(this.sessionForm, 'xingbie', null);
			}
			if ('yonghu' == this.userTableName) {
				this.$set(this.sessionForm, 'nianling', null);
			}
			if ('yonghu' == this.userTableName) {
				this.$set(this.sessionForm, 'youxiang', null);
			}
			if ('yonghu' == this.userTableName) {
				this.$set(this.sessionForm, 'mobile', null);
			}
			if ('yonghu' == this.userTableName) {
				this.$set(this.sessionForm, 'money', null);
			}

			if ('yonghu' == this.userTableName&&this.rules['yonghuming']){
				this.rules['yonghuming'].push({ required: true, message: 'иҜ·иҫ“е…Ҙз”ЁжҲ·еҗҚ', trigger: 'blur' })
			}else if('yonghu' == this.userTableName&&!this.rules['yonghuming']) {
				this.$set(this.rules, 'yonghuming', [{ required: true, message: 'иҜ·иҫ“е…Ҙз”ЁжҲ·еҗҚ', trigger: 'blur' }]);
			}
			if ('yonghu' == this.userTableName&&this.rules['mima']){
				this.rules['mima'].push({ required: true, message: 'иҜ·иҫ“е…ҘеҜҶз Ғ', trigger: 'blur' })
			}else if('yonghu' == this.userTableName&&!this.rules['mima']) {
				this.$set(this.rules, 'mima', [{ required: true, message: 'иҜ·иҫ“е…ҘеҜҶз Ғ', trigger: 'blur' }]);
			}
			if ('yonghu' == this.userTableName&&this.rules['xingming']){
				this.rules['xingming'].push({ required: true, message: 'иҜ·иҫ“е…Ҙе§“еҗҚ', trigger: 'blur' })
			}else if('yonghu' == this.userTableName&&!this.rules['xingming']) {
				this.$set(this.rules, 'xingming', [{ required: true, message: 'иҜ·иҫ“е…Ҙе§“еҗҚ', trigger: 'blur' }]);
			}
			if ('yonghu' == this.userTableName) {
				this.$set(this.rules, 'nianling', [{ required: false, validator: this.$validate.isIntNumer, trigger: 'blur' }]);
			}
			if ('yonghu' == this.userTableName) {
				this.$set(this.rules, 'youxiang', [{ required: false, validator: this.$validate.isEmail, trigger: 'blur' }]);
			}
			if ('yonghu' == this.userTableName) {
				this.$set(this.rules, 'mobile', [{ required: false, validator: this.$validate.isMobile, trigger: 'blur' }]);
			}
			if ('yonghu' == this.userTableName) {
				this.$set(this.rules, 'money', [{ required: false, validator: this.$validate.isNumber, trigger: 'blur' }]);
			}

			this.init();
			this.sessionForm = JSON.parse(localStorage.getItem('sessionForm'))
		},
		//ж–№жі•йӣҶеҗҲ
		methods: {
			init() {
				if ('yonghu' == this.userTableName) {
					this.dynamicProp.xingbie = 'з”·,еҘі'.split(',');
				}
			},
			setSession(){
				localStorage.setItem('sessionForm',JSON.stringify(this.sessionForm))
			},
			onSubmit(formName) {
				if(`yonghu` == this.userTableName && this.sessionForm.touxiang!=null){
					this.sessionForm.touxiang = this.sessionForm.touxiang.replace(new RegExp(this.$config.baseUrl,"g"),"");
				}
				this.$refs[formName].validate((valid) => {
					if (valid) {
						this.$http.post(this.userTableName + '/update', this.sessionForm).then(res => {
							if (res.data.code == 0) {
								this.setSession()
								this.$message({
									message: 'жӣҙж–°жҲҗеҠҹ',
									type: 'success',
									duration: 1500
								});
							}
						});
					} else {
						return false;
					}
				});
			},
			yonghutouxiangHandleAvatarSuccess(fileUrls) {
				this.sessionForm.touxiang = fileUrls;
			},
			chongzhi() {
				if (this.chongzhiForm.money == '') {
					this.$message({
						message: 'иҜ·иҫ“е…Ҙе……еҖјйҮ‘йўқ',
						type: 'error',
						duration: 1500
					});
					return;
				}
				if (this.chongzhiForm.money <= 0) {
					this.$message({
						message: 'иҜ·иҫ“е…ҘжӯЈзЎ®зҡ„е……еҖјйҮ‘йўқ',
						type: 'error',
						duration: 1500
					});
					return;
				}
				if (this.chongzhiForm.radio == '') {
					this.$message({
						message: 'иҜ·йҖүжӢ©е……еҖјж–№ејҸ',
						type: 'error',
						duration: 1500
					});
					return;
				}
				if(!this.sessionForm.money) {
					this.sessionForm.money = parseFloat(this.chongzhiForm.money)
				}else{
					this.sessionForm.money = parseFloat(this.sessionForm.money) + parseFloat(this.chongzhiForm.money);
				}
				
				this.$http.post(this.userTableName + '/update', this.sessionForm).then(res => {
					if (res.data.code == 0) {
						this.$http.post('chargerecord/add',{
							username: localStorage.getItem("username"),
							role: localStorage.getItem("frontRole"),
							amount: parseFloat(this.chongzhiForm.money),
							userid: this.sessionForm.id
						}).then(rs=>{
							this.setSession()
							this.$message({
								message: 'е……еҖјжҲҗеҠҹ',
								type: 'success',
								duration: 1500,
								onClose: () => {
									this.dialogFormVisibleMoney = false;
								}
							});
						})
					}
				});
			},
			handleClick(tab, event) {
				switch(event.target.outerText) {
					case 'дёӘдәәдёӯеҝғ':
						tab.$router.push('/index/center');
						break;
					case 'дҝ®ж”№еҜҶз Ғ':
						this.passwordForm = {
							password: '',
							newpassword: '',
							repassword: '',
						}
						this.$forceUpdate()
						break;
					case 'жҲ‘зҡ„и®ўеҚ•':
						tab.$router.push('/index/shop-order/order');
						break;
					case 'жҲ‘зҡ„ең°еқҖ':
						tab.$router.push('/index/shop-address/list');
						break;
					case 'жҲ‘зҡ„ж”¶и—Ҹ':
						localStorage.setItem('storeupType', 1);
						tab.$router.push('/index/storeup');
						break;
					case 'жҲ‘зҡ„дјҳжғ еҲё':
						this.getMyList()
						break;
					default:
						tab.$router.push(`/index/${tab.name}?centerType=1`);
				}

				this.title = event.target.outerText;
			},
			async updatePassword(){
				this.$refs["passwordForm"].validate(async valid => {
					if (valid) {
						var password = "";
						if (this.sessionForm.mima) {
							password = this.sessionForm.mima;
						} else if (this.sessionForm.password) {
							password = this.sessionForm.password;
						}
						if (this.userTableName == 'yonghu') {
						}
						var nowpassword = ''
						await this.$http.get('encrypt/md5?text=' + this.passwordForm.password,).then(res=>{
							if(res.data&&res.data.code==0){
								nowpassword = res.data.data
							}
						})
						if(nowpassword!=password){
							this.$message.error("еҺҹеҜҶз Ғй”ҷиҜҜ");
							return;
						}
						if (this.passwordForm.newpassword != this.passwordForm.repassword) {
							this.$message.error("дёӨж¬ЎеҜҶз Ғиҫ“е…ҘдёҚдёҖиҮҙ");
							return;
						}
						if (this.passwordForm.newpassword == this.passwordForm.password) {
							this.$message.error("ж–°еҜҶз ҒдёҺеҺҹеҜҶз ҒзӣёеҗҢпјҒ");
							return;
						}
						this.sessionForm.password = this.passwordForm.newpassword;
						this.sessionForm.mima = this.passwordForm.newpassword;
						this.$http.post(`${this.userTableName}/update`,this.sessionForm).then(({data})=>{
							if (data && data.code === 0) {
								this.$message({
									message: "дҝ®ж”№еҜҶз ҒжҲҗеҠҹ,дёӢж¬Ўзҷ»еҪ•зі»з»ҹз”ҹж•Ҳ",
									type: "success",
									duration: 1500,
									onClose: () => {
									}
								});
								this.setSession()
							} else {
								this.$message.error(data.msg);
							}
						});
					}
				})
			},
			logout() {
				localStorage.clear();
				Vue.http.headers.common['Token'] = "";
				this.$router.push('/index/home');
				this.activeIndex = '0'
				localStorage.setItem('keyPath', this.activeIndex)
				this.$forceUpdate()
				this.$message({
					message: 'зҷ»еҮәжҲҗеҠҹ',
					type: 'success',
					duration: 1500,
				});
			},
			getMyList() {
				this.$http.get('mycoupon/page').then(res => {
					if (res.data && res.data.code == 0) {
						for (let x in res.data.data.list) {
							if (!this.isBetweenTime(this.getCurDateTime(), [res.data.data.list[x].startime, res
									.data.data.list[x].endtime
								]) && res.data.data.list[x].status != 'е·ІдҪҝз”Ё' && res.data.data.list[x].status !=
								'е·ІиҝҮжңҹ') {
								res.data.data.list[x].status = 'е·ІиҝҮжңҹ'
								this.$http.post('mycoupon/update', res.data.data.list[x]).then(obj => {})
							} else if (this.isBetweenTime(this.getCurDateTime(), [res.data.data.list[x]
									.startime, res.data.data.list[x].endtime
								]) && res.data.data.list[x].status != 'е·ІдҪҝз”Ё' && res.data.data.list[x].status !=
								'еҸҜдҪҝз”Ё') {
								res.data.data.list[x].status = 'еҸҜдҪҝз”Ё'
								this.$http.post('mycoupon/update', res.data.data.list[x]).then(obj => {})
							}
						}
						this.couponList = res.data.data.list
					}
				})
			},
			isBetweenTime(currentDate, timeQuantum) {
				let isBetween = true;
				let currentTime = new Date(currentDate);
				let startTime = new Date(timeQuantum[0]);
				let endTime = new Date(timeQuantum[1]);
				let t1 = currentTime.getTime() - startTime.getTime();
				let t2 = currentTime.getTime() - endTime.getTime();
				if (t1 < 0 || t2 > 0) {
					isBetween = false;
				}
				return isBetween;
			},
			hasBack(name){
				switch(name){
					case 'и®ўеҚ•з®ЎзҗҶ':
						return false
						break;
					case 'жҲ‘зҡ„ж”¶и—Ҹз®ЎзҗҶ':
						return false
						break;
					default:
						return true
				}
			}
		}
	}
