<script>
// import { Message } from "element-ui";
export default {
  data() {
    return {
      name: "",
      account: "",
      type: "",
      table: "",
      obj: ""
    };
  },
  mounted() {
    let table = localStorage.getItem("paytable");
    let obj = JSON.parse(localStorage.getItem("payObject"));
    this.table = table;
    this.obj = obj;
  },
  methods: {
    submitTap() {
      // if (!this.name) {
      //   this.$message.error("иҜ·иҫ“е…Ҙж”¶ж¬ҫдәәе§“еҗҚ");
      //   return;
      // }
      // if (!this.account) {
      //   this.$message.error("иҜ·иҫ“е…Ҙж”¶ж¬ҫдәәиҙҰеҸ·");
      //   return;
      // }
      if (!this.type) {
        this.$message.error("иҜ·йҖүжӢ©ж”Ҝд»ҳж–№ејҸ");
        return;
      }
      this.$confirm(`зЎ®е®ҡж”Ҝд»ҳ?`, "жҸҗзӨә", {
        confirmButtonText: "зЎ®е®ҡ",
        cancelButtonText: "еҸ–ж¶Ҳ",
        type: "warning"
      }).then(() => {
        this.obj.ispay = "е·Іж”Ҝд»ҳ";
        this.$http.post(`${this.table}/update`,this.obj).then(res => {
          if (res.data && res.data.code === 0) {
            this.$message({
              message: "ж”Ҝд»ҳжҲҗеҠҹ",
              type: "success",
              duration: 1500,
              onClose: () => {
                this.$router.go(-1);
              }
            });
          } else {
            this.$message.error(res.data.msg);
          }
        });
      });
    },
    back(){
      this.$router.go(-1);
    }
  }
};
</script>
