<template>
	<div :style='{"padding":"0 0 20px","margin":"0px auto","color":"#666","background":"#fff","width":"1200px","fontSize":"16px","position":"relative"}'>
		<div class="back_box">
			<el-button class="backBtn" size="mini" @click="backClick">
				<span class="icon iconfont icon-jiantou33"></span>
				<span class="text">иҝ”еӣһ</span>
			</el-button>
		</div>
		<div class="section-title" :style='{"padding":"0","margin":"0 1060px 20px 0","color":"#fff","borderRadius":"0px 0px 30px 30px","textAlign":"center","background":"#5FB6B8","display":"inline-block","width":"190px","fontSize":"22px","lineHeight":"60px","height":"60px"}'>жҲ‘зҡ„и®ўеҚ•</div>
		<el-tabs v-model="activeName" @tab-click="handleClick">
			<el-tab-pane label="жңӘж”Ҝд»ҳ" name="жңӘж”Ҝд»ҳ"></el-tab-pane>
			<el-tab-pane label="е·Іж”Ҝд»ҳ" name="е·Іж”Ҝд»ҳ"></el-tab-pane>
			<el-tab-pane label="е·ІеҸ‘иҙ§" name="е·ІеҸ‘иҙ§"></el-tab-pane>
			<el-tab-pane label="е·Іе®ҢжҲҗ" name="е·Іе®ҢжҲҗ"></el-tab-pane>
			<el-tab-pane label="е·ІйҖҖж¬ҫ" name="е·ІйҖҖж¬ҫ"></el-tab-pane>
			<el-tab-pane label="е·ІеҸ–ж¶Ҳ" name="е·ІеҸ–ж¶Ҳ"></el-tab-pane>
		</el-tabs>
		<el-table :data="tableData" style="width: 100%">
			<el-table-column label="и®ўеҚ•зј–еҸ·" prop="orderid"></el-table-column>
			<el-table-column label="е•Ҷе“Ғ" align="center" width="200px">
				<template slot-scope="scope">
					<div class="shangpin">
						<el-image style="width: 100px; height: 100px;flex: 1" :src="baseUrl + scope.row.picture" fit="fill"></el-image>
						<span style="margin-left: 10px;flex: 1" >{{ scope.row.goodname }}</span>
					</div>
				</template>
			</el-table-column>
			<el-table-column label="д»·ж ј">
				<template slot-scope="scope">
					<span v-if="(scope.row.type == 1 || scope.row.type == 3)&&scope.row.price>0"><span :style='{"fontSize":"12px"}'>пҝҘ</span>{{ scope.row.price }}</span>
					<span v-if="scope.row.type == 2&&scope.row.price>0">{{ scope.row.price }}з§ҜеҲҶ</span>
				</template>
			</el-table-column>
			<el-table-column label="ж•°йҮҸ" prop="buynumber"></el-table-column>
			<el-table-column label="жҖ»д»·">
				<template slot-scope="scope">
					<span v-if="(scope.row.type == 1 || scope.row.type == 3)&&scope.row.total>0"><span :style='{"fontSize":"12px"}'>пҝҘ</span>{{ scope.row.total }}</span>
					<span v-if="scope.row.type == 2&&scope.row.total>0">{{ scope.row.total }}з§ҜеҲҶ</span>
				</template>
			</el-table-column>
			<el-table-column label="ең°еқҖ" prop="address"></el-table-column>
			<el-table-column label="з”өиҜқ" prop="tel"></el-table-column>
			<el-table-column label="ж”¶иҙ§дәә" prop="consignee"></el-table-column>
			<el-table-column label="дёӢеҚ•ж—¶й—ҙ" prop="addtime"></el-table-column>
			<el-table-column label="еӨҮжіЁ" prop="remark"></el-table-column>
			<el-table-column label="йҖҖиҙ§е®Ўж ё" prop="sfsh" v-if="changeReturnGoods()">
				<template slot-scope="scope">
					<el-tag type="success" v-if="scope.row.sfsh=='жҳҜ'">е·ІйҖҡиҝҮ</el-tag>
					<el-tag type="warning" v-if="scope.row.sfsh=='еҫ…е®Ўж ё'">еҫ…е®Ўж ё</el-tag>
					<el-tag type="danger" v-if="scope.row.sfsh=='еҗҰ'">жңӘйҖҡиҝҮ</el-tag>
				</template>
			</el-table-column>
			<el-table-column label="е®Ўж ёеӣһеӨҚ" prop="shhf"></el-table-column>
			<el-table-column label="ж“ҚдҪң" width="150">
				<template slot-scope="scope">
					<el-button v-show="activeName == 'жңӘж”Ҝд»ҳ'" type="success" :style='{"margin":"2px auto",}' size="mini" @click="pay(scope.row)">ж”Ҝд»ҳ</el-button>
					<el-button v-show="activeName == 'жңӘж”Ҝд»ҳ'" type="danger" :style='{"margin":"2px auto",}' size="mini" @click="cancel(scope.row)">еҸ–ж¶Ҳ</el-button>
					<el-button v-show="activeName == 'е·Іж”Ҝд»ҳ'" type="danger" :style='{"margin":"2px auto",}' size="mini" @click="refund(scope.row)">{{scope.row.total>0?'йҖҖж¬ҫ':'йҖҖи®ў'}}</el-button>
					<el-button v-if="scope.row.logistics" type="warning" :style='{"margin":"2px auto",}' size="mini" @click="logistics(scope.row)">зү©жөҒ</el-button>
					<el-button v-if="activeName == 'е·Іе®ҢжҲҗ'&&scope.row.sfsh==''&&changeReturnGoods()" type="danger" :style='{"margin":"2px auto",}' size="mini" @click="returnGood(scope.row)">йҖҖиҙ§</el-button>
					<el-button v-show="activeName == 'е·Іе®ҢжҲҗ'" type="primary" :style='{"margin":"2px auto",}' size="mini" @click="toDetail(scope.row)">иҜ„д»·</el-button>
					<el-button v-show="activeName == 'е·ІеҸ‘иҙ§'" type="success" :style='{"margin":"2px auto",}' size="mini" @click="confirm(scope.row)">зЎ®и®Өж”¶иҙ§</el-button>
				</template>
			</el-table-column>
		</el-table>
		<el-pagination
			background
			id="pagination" class="pagination"
			:pager-count="7"
			:page-size="pageSize"
			:page-sizes="pageSizes"
			prev-text="<"
			next-text=">"
			:hide-on-single-page="false"
			:layout='["total","prev","pager","next","sizes","jumper"].join()'
			:total="total"
			:style='{"padding":"0","boxShadow":"0px 4px 10px 0px rgba(0,0,0,0.3)","margin":"20px auto","whiteSpace":"nowrap","color":"#333","alignItems":"center","textAlign":"center","display":"flex","clear":"both","justifyContent":"center","overflow":"hidden","borderRadius":"30px","width":"100%","fontSize":"16px","fontWeight":"500","order":"50","height":"60px","maxWidth":"800px"}'
			@current-change="curChange"
			@prev-click="prevClick"
			@next-click="nextClick"
			></el-pagination>

		<el-dialog title="зү©жөҒдҝЎжҒҜ" :visible.sync="logisticsVisible" width="30%">
			<div class="ql-snow ql-editor" v-html="logisticsText"></div>
		</el-dialog>
		<el-dialog title="йҖҖиҙ§зҗҶз”ұ" :visible.sync="returngoodVisible" width="30%">
			<el-input v-model="returnGoodForm.returnreason" type="textarea" placeholder="йҖҖиҙ§зҗҶз”ұ"></el-input>
			<div style="margin: 20px 0 0">
				<el-button type="primary" style="margin-left: 10px;" @click="returnGoodSave">зЎ®и®Ө</el-button>
				<el-button type="danger" style="margin-left: 10px;" @click="returngoodVisible=false">еҸ–ж¶Ҳ</el-button>
			</div>
		</el-dialog>
	
	</div>
</template>

<script>
	import config from '@/config/config'
	export default {
		data() {
			return {
				layouts: '',
				baseUrl: config.baseUrl,
				activeName: 'жңӘж”Ҝд»ҳ',
				tableData: [],
				total: 1,
				pageSize: 10,
				pageSizes: [],
				totalPage: 1,
				session: {},
				userTableName: localStorage.getItem('UserTableName'),
				logisticsVisible: false,
				logisticsText: '',
				returngoodVisible: false,
				returnGoodForm: {},
			}
		},
		created() {
			this.getSession();
			this.getMyOrderList(1);
		},
		methods: {
			backClick() {
				this.$router.push('/index/center')
			},
			getSession() {
				this.$http.get(this.userTableName+'/session', {emulateJSON: true}).then(res => {
					if (res.data.code == 0) {
						this.session = res.data.data;
					}
				});
			},
			handleClick(tab, event) {
				tab.activeName = event.target.outerText;
				this.getMyOrderList(1);
			},
			toDetail(row) {
				this.$router.push({path: '/index/'+row.tablename+'Detail', query: {id: row.goodid}});
			},
			handleAction(index, row) {
				if (index == 'е·Іж”Ҝд»ҳ' && this.session.money < row.total) {
					this.$message.error('дҪҷйўқдёҚи¶іпјҢиҜ·е…Ҳе……еҖј');
					return;
				}
	
				row.status = index;
				this.$http.post('orders/update', row).then(res => {
					if (res.data.code == 0) {
						if (index == 'е·Іж”Ҝд»ҳ') this.session.money -= row.total;
						if (index == 'е·ІйҖҖж¬ҫ' && row.type == 1) this.session.money += row.total;
						if (index == 'е·ІйҖҖж¬ҫ' && row.type == 2) this.session.jifen += row.total;
						if (index == 'е·Іж”Ҝд»ҳ' || index == 'е·ІйҖҖж¬ҫ') {
							this.session.money = this.session.money.toFixed(2);
							this.$http.post(this.userTableName+'/update', this.session).then(res => {});
						}
						this.$message({
							message: 'ж“ҚдҪңжҲҗеҠҹ',
							type: 'success',
							duration: 1500,
							onClose: () => {
								this.getMyOrderList(1);
							}
						});
					}
				});
			},
			// йҖҖж¬ҫ
			refund(item) {
				this.$confirm(`${item.total>0?'зЎ®е®ҡйҖҖж¬ҫеҗ—пјҹйҖҖж¬ҫйҮ‘йўқе°Ҷиҝ”еӣһиҙҰжҲ·дёӯгҖӮ':'жҳҜеҗҰйҖҖи®ўпјҹ'}`, "жҸҗзӨә", {
					confirmButtonText: "зЎ®е®ҡ",
					cancelButtonText: "еҸ–ж¶Ҳ",
					type: "warning"
				}).then(() => {
					// иҺ·еҸ–е•Ҷе“ҒиҜҰжғ…дҝЎжҒҜ
					this.$http.get(item.tablename+'/info/'+item.goodid, {}).then(res => {
						// е•Ҷе“ҒдҝЎжҒҜ
						let good = res.data.data;
						// з”ЁжҲ·еҪ“еүҚз”ЁжҲ·дҝЎжҒҜ
						let table = localStorage.getItem("UserTableName");
						this.$http.get(table+'/session', {}).then(res => {
							this.user = res.data.data;
							if(item.type==1||item.type==3) {
								// еҰӮжһңиҜҘе•Ҷе“ҒеӯҳеңЁз§ҜеҲҶ
								if (good.jf) {
									this.user.jf = (Number(this.user.jf) - Number(item.total)).toFixed(2);
								}
								this.user.money = (Number(this.user.money) + Number(item.total)).toFixed(2);
								// жӣҙж–°з”ЁжҲ·дҪҷйўқ
								this.$http.post(table+'/update', this.user).then(res => {
									item.status = 'е·ІйҖҖж¬ҫ'
									localStorage.setItem('sessionForm',JSON.stringify(this.user))
									this.$http.post(`orders/update`, item).then(res => {
										if(item.tablename == `shangpinxinxi`){
											// еҠ еӣһеә“еӯҳж•°йҮҸ
											good.alllimittimes = good.alllimittimes + item.buynumber;
											this.$http.post(`shangpinxinxi/update`, good).then(res => {
											});
										}
										this.$message({
											message: `${item.total>0?'йҖҖж¬ҫжҲҗеҠҹ':'йҖҖи®ўжҲҗеҠҹ'}`,
											type: 'success',
											duration: 1500,
											onClose: () => {
												this.getMyOrderList(1);
											}
										});
									});
								});
							} else if(item.type==2) {
								this.user.jf = Number(this.user.jf) + Number(item.total);
								// жӣҙж–°з”ЁжҲ·дҪҷйўқ
								this.$http.post(table+'/update', this.user).then(res => {
									item.status = 'е·ІйҖҖж¬ҫ'
									localStorage.setItem('sessionForm',JSON.stringify(this.user))
									this.$http.post(`orders/update`, item).then(res => {
										if(item.tablename == `shangpinxinxi`){
											// еҠ еӣһеә“еӯҳж•°йҮҸ
											good.alllimittimes = good.alllimittimes + item.buynumber;
											this.$http.post(`shangpinxinxi/update`, good).then(res => {
											});
										}
										this.$message({
											message: `${item.total>0?'йҖҖж¬ҫжҲҗеҠҹ':'йҖҖи®ўжҲҗеҠҹ'}`,
											type: 'success',
											duration: 1500,
											onClose: () => {
												this.getMyOrderList(1);
											}
										});
									});
								});
							}
						});
					});
				});
			},
			//зү©жөҒ
			logistics(row) {
				this.logisticsText = row.logistics;
				this.logisticsVisible = true;
			},
			//йҖҖиҙ§
			returnGood(item){
				this.returnGoodForm = item
				this.returngoodVisible = true
			},
			returnGoodSave() {
				this.$confirm(`зЎ®е®ҡйҖҖиҙ§еҗ—пјҹе®Ўж ёйҖҡиҝҮеҗҺйҖҖж¬ҫйҮ‘йўқе°Ҷиҝ”еӣһиҙҰжҲ·дёӯгҖӮ`, "жҸҗзӨә", {
					confirmButtonText: "зЎ®е®ҡ",
					cancelButtonText: "еҸ–ж¶Ҳ",
					type: "warning"
				}).then(() => {
					this.returnGoodForm.sfsh = 'еҫ…е®Ўж ё'
					this.$http.post(`orders/update`, this.returnGoodForm).then(res => {
						this.$message({
							message: 'з”іиҜ·жҲҗеҠҹ',
							type: 'success',
							duration: 1500,
							onClose: () => {
								this.getMyOrderList(1);
								this.returngoodVisible = false
							}
						});
					})
				});
			},

			// ж”Ҝд»ҳ
			pay(item) {
				// иҺ·еҸ–е•Ҷе“ҒиҜҰжғ…дҝЎжҒҜ
				this.$http.get(item.tablename+'/info/'+item.goodid, {}).then(res => {
					// е•Ҷе“ҒдҝЎжҒҜ
					let data = res.data.data;
					// з”ЁжҲ·еҪ“еүҚз”ЁжҲ·дҝЎжҒҜ
					let table = localStorage.getItem("UserTableName");
					this.$http.get(table+'/session', {}).then(res => {
						this.user = res.data.data;
						// еҲӨж–ӯдҪҷйўқжҳҜеҗҰе……и¶і
						if (Number(this.user.money) < Number(item.total)) {
							this.$message({
								message: 'дҪҷйўқдёҚи¶іпјҢиҜ·е…Ҳе……еҖј',
								type: 'error',
								duration: 1500
							});
							return
						}
						// еҰӮжһңиҜҘе•Ҷе“ҒеӯҳеңЁз§ҜеҲҶ
						if (data.jf) {
							this.user.jf = Number((Number(this.user.jf) + Number(item.total)).toFixed(2));
						}
						this.user.money = Number((Number(this.user.money) - Number(item.total)).toFixed(2));
						// жӣҙж–°з”ЁжҲ·дҪҷйўқ
						this.$http.post(table+'/update', this.user).then(res => {
							item.status = 'е·Іж”Ҝд»ҳ'
							localStorage.setItem('sessionForm',JSON.stringify(this.user))
							this.$http.post(`orders/update`, item).then(res => {
								this.$message({
									message: 'ж”Ҝд»ҳжҲҗеҠҹ',
									type: 'success',
									duration: 1500,
									onClose: () => {
										this.getMyOrderList(1);
									}
								});
							});
						});
					});
				});
			},
			confirm(item){
				this.$confirm(`жҳҜеҗҰзЎ®е®ҡж”¶иҙ§пјҹ`, "жҸҗзӨә", {
					confirmButtonText: "зЎ®е®ҡ",
					cancelButtonText: "еҸ–ж¶Ҳ",
					type: "warning"
				}).then(() => {
					item.status = 'е·Іе®ҢжҲҗ'
					this.$http.post(`orders/update`, item).then(res => {
						this.$message({
							message: 'зЎ®и®Өж”¶иҙ§жҲҗеҠҹ',
							type: 'success',
							duration: 1500,
							onClose: () => {
								this.getMyOrderList(1);
							}
						});
					});
				});
			},
			cancel(item){
				this.$confirm(`жҳҜеҗҰеҸ–ж¶Ҳи®ўеҚ•пјҹ`, "жҸҗзӨә", {
					confirmButtonText: "зЎ®е®ҡ",
					cancelButtonText: "еҸ–ж¶Ҳ",
					type: "warning"
				}).then(() => {
					item.status = 'е·ІеҸ–ж¶Ҳ'
					this.$http.post(`orders/update`, item).then(res => {
						// иҺ·еҸ–е•Ҷе“ҒиҜҰжғ…дҝЎжҒҜ
						this.$http.get(item.tablename+'/info/'+item.goodid, {}).then(res => {
							// е•Ҷе“ҒдҝЎжҒҜ
							let good = res.data.data;
							if(item.tablename == `shangpinxinxi`){
								// еҠ еӣһеә“еӯҳж•°йҮҸ
								good.alllimittimes = good.alllimittimes + item.buynumber;
								this.$http.post(`shangpinxinxi/update`, good).then(res => {
								});
							}
							this.$message({
								message: 'и®ўеҚ•еҸ–ж¶ҲжҲҗеҠҹ',
								type: 'success',
								duration: 1500,
								onClose: () => {
									this.getMyOrderList(1);
								}
							});
						});
					});
				});
			},
			getMyOrderList(page) {
				this.$http.get('orders/list', {params: {page, limit: this.pageSize,sort:'addtime',order:'desc', userid: localStorage.getItem('frontUserid'), status: this.activeName}}).then(res => {
					if (res.data.code == 0) {
						this.tableData = res.data.data.list;
						this.total = res.data.data.total;
						this.pageSize = Number(res.data.data.pageSize);
						this.totalPage = res.data.data.totalPage;
						if(this.pageSizes.length==0){
							this.pageSizes = [this.pageSize, this.pageSize*2, this.pageSize*3, this.pageSize*5];
						}
					}
				});
			},
			curChange(page) {
				this.getMyOrderList(page);
			},
			prevClick(page) {
				this.getMyOrderList(page);
			},
			nextClick(page) {
				this.getMyOrderList(page);
			}
		}
	}
</script>

<style rel="stylesheet/scss" lang="scss" scoped>
	.section {
		width: 1000px;
		margin: 0 auto;
	}

	.shangpin {
		display: flex;
	}
	
</style>
